/**
 * House of Athletes - Google Apps Script Backend
 * Updated with encrypted PIN storage
 * 
 * IMPORTANT: PINs are already hashed by the frontend using SHA-256
 * This script stores and compares hashes only
 */

/**
 * Hash a PIN using SHA-256 with phone as salt
 * NOTE: This function is for testing only
 * The frontend hashes PINs before sending them here
 * 
 * @param {string} pin - 4-digit PIN
 * @param {string} phone - User's phone number (used as salt)
 * @returns {string} - 64-character hashed PIN
 */
function hashPin(pin, phone) {
  const combined = pin + phone;

  const hash = Utilities.computeDigest(
    Utilities.DigestAlgorithm.SHA_256,
    combined,
    Utilities.Charset.UTF_8
  );

  // Convert byte array to hex string
  const hexString = hash.map(function(byte) {
    const v = (byte < 0) ? 256 + byte : byte;
    return ("0" + v.toString(16)).slice(-2);
  }).join("");

  return hexString;
}

/**
 * Setup PIN for a member
 * Receives ALREADY HASHED PIN from frontend
 * MODIFIED: Allows overwriting existing PINs (Reset functionality)
 */
function setupPin(phone, hashedPin) {
  try {
    const spreadsheet = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = spreadsheet.getSheetByName('CONTRACTS');
    if (!sheet) return { success: false, message: 'CONTRACTS sheet not found' };

    const dataRange = sheet.getDataRange();
    const values = dataRange.getValues();
    const HEADER_ROW = 7;
    const headers = values[HEADER_ROW];

    const phoneIndex = headers.findIndex(h => h.toString().toLowerCase().includes('phone'));
    let pinIndex = headers.findIndex(h => h.toString().toLowerCase().includes('pin'));

    if (pinIndex === -1) {
      pinIndex = headers.length;
      sheet.getRange(HEADER_ROW + 1, pinIndex + 1).setValue('PIN');
    }

    if (phoneIndex === -1) return { success: false, message: 'Phone column not found' };

    const cleanPhone = phone.replace(/[\s\-\(\)]/g, '');
    let foundRow = -1;

    for (let i = HEADER_ROW + 1; i < values.length; i++) {
      const rowPhone = values[i][phoneIndex]?.toString().replace(/[\s\-\(\)]/g, '');
      if (rowPhone && rowPhone.includes(cleanPhone.slice(-10))) {
        foundRow = i + 1;
        break;
      }
    }

    if (foundRow === -1) return { success: false, message: 'Phone number not found' };

    // MODIFICATION: Removed the "PIN already exists" check.
    // We now simply overwrite the PIN to allow resets.
    sheet.getRange(foundRow, pinIndex + 1).setValue(hashedPin);

    return { success: true, message: 'PIN successfully updated' };

  } catch (error) {
    return { success: false, message: 'Server error: ' + error.toString() };
  }
}

/**
 * Login member with encrypted PIN
 * Receives ALREADY HASHED PIN from frontend and compares with stored hash
 * 
 * @param {string} phone - User's phone number
 * @param {string} hashedPin - Already hashed PIN from frontend (64 chars)
 * @returns {object} - Login response with member data or error
 */
function loginMember(phone, hashedPin) {
  try {
    const spreadsheet = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = spreadsheet.getSheetByName('CONTRACTS');

    if (!sheet) {
      return {
        success: false,
        message: 'CONTRACTS sheet not found'
      };
    }

    const dataRange = sheet.getDataRange();
    const values = dataRange.getValues();

    const HEADER_ROW = 7;
    const headers = values[HEADER_ROW];
    const data = values.slice(HEADER_ROW + 1);

    const phoneIndex = headers.findIndex(h => h.toString().toLowerCase().includes('phone'));
    const pinIndex = headers.findIndex(h => h.toString().toLowerCase().includes('pin'));

    if (phoneIndex === -1) {
      return {
        success: false,
        message: 'Phone column not found in spreadsheet'
      };
    }

    // Clean phone number
    const cleanPhone = phone.replace(/[\s\-\(\)]/g, '');

    // Find member
    let memberRow = null;
    for (let i = 0; i < data.length; i++) {
      const rowPhone = data[i][phoneIndex]?.toString().replace(/[\s\-\(\)]/g, '');
      if (rowPhone && rowPhone.includes(cleanPhone.slice(-10))) {
        memberRow = data[i];
        break;
      }
    }

    if (!memberRow) {
      return {
        success: false,
        message: 'Phone number not found in database'
      };
    }

    // Get stored hash from sheet
    const storedHash = memberRow[pinIndex]?.toString().trim();

    // Check if PIN exists
    if (!storedHash || storedHash === '') {
      return {
        success: true,
        needsPin: true
      };
    }

    // Compare hashed PINs (simple string comparison)
    if (hashedPin !== storedHash) {
      Logger.log('Login failed for phone: ' + phone + ' (invalid PIN)');
      return {
        success: true,
        invalidPin: true
      };
    }

    // Build member object
    const member = {
      firstName: memberRow[headers.findIndex(h => h.toString().includes('First Name'))] || '',
      lastName: memberRow[headers.findIndex(h => h.toString().includes('Last Name'))] || '',
      email: memberRow[headers.findIndex(h => h.toString().toLowerCase().includes('email'))] || '',
      phone: memberRow[phoneIndex] || '',
      package: memberRow[headers.findIndex(h => h.toString().toLowerCase().includes('package'))] || '',
      amount: memberRow[headers.findIndex(h => h.toString().toLowerCase().includes('amount'))] || '',
      duration: memberRow[headers.findIndex(h => h.toString().toLowerCase().includes('duration'))] || '',
      startDate: formatDate(memberRow[headers.findIndex(h => h.toString().includes('Start Date'))]),
      expirationDate: formatDate(memberRow[headers.findIndex(h => h.toString().includes('Expiration Date'))]),
      status: memberRow[headers.findIndex(h => h.toString().toLowerCase().includes('status'))] || '',
      pauseDays: memberRow[headers.findIndex(h => h.toString().includes('Pause Days'))] || '0'
    };

    Logger.log('Login successful for phone: ' + phone);

    return {
      success: true,
      member: member
    };

  } catch (error) {
    Logger.log('Login error: ' + error.toString());
    return {
      success: false,
      message: 'Server error: ' + error.toString()
    };
  }
}

/**
 * Format date helper function
 */
function formatDate(dateValue) {
  if (!dateValue) return '';

  if (typeof dateValue === 'string') return dateValue;

  if (dateValue instanceof Date) {
    const day = dateValue.getDate();
    const month = dateValue.toLocaleString('default', { month: 'short' });
    const year = dateValue.getFullYear();
    return `${day} ${month} ${year}`;
  }

  return dateValue.toString();
}

/**
 * Main web app entry point
 * Handles POST requests from frontend
 * Now supports both encrypted and legacy requests
 */
function doPost(e) {
  try {
    // Parse the incoming request
    const data = JSON.parse(e.postData.contents);
    const phone = data.phone;
    const action = data.action;

    // Validate phone
    if (!phone) {
      return ContentService.createTextOutput(JSON.stringify({
        success: false,
        message: 'Phone number is required'
      })).setMimeType(ContentService.MimeType.JSON);
    }

    // Handle different actions
    if (action === 'setupPin') {
      // Encrypted PIN setup
      const hashedPin = data.hashedPin;

      if (!hashedPin) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'PIN is required'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      return ContentService.createTextOutput(
        JSON.stringify(setupPin(phone, hashedPin))
      ).setMimeType(ContentService.MimeType.JSON);

    } else if (action === 'login') {
      // Encrypted PIN login
      const hashedPin = data.hashedPin;

      if (!hashedPin) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'PIN is required'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      return ContentService.createTextOutput(
        JSON.stringify(loginMember(phone, hashedPin))
      ).setMimeType(ContentService.MimeType.JSON);

    } else if (action === 'saveNotificationToken') {
      // NEW: Save notification token
      // This block is now reachable because it is before the legacy else
      return ContentService.createTextOutput(
        JSON.stringify(saveNotificationToken(data.phone, data.token))
      ).setMimeType(ContentService.MimeType.JSON);

    } else {
      // Legacy support (for old plain-text PIN - will be phased out)
      const pin = data.pin;

      if (!pin) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'PIN is required'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      // Validate PIN format (4 digits)
      if (!/^\d{4}$/.test(pin)) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'PIN must be exactly 4 digits'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      // Get sheet
      const spreadsheet = SpreadsheetApp.getActiveSpreadsheet();
      const sheet = spreadsheet.getSheetByName('CONTRACTS');

      if (!sheet) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'CONTRACTS sheet not found'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      const dataRange = sheet.getDataRange();
      const values = dataRange.getValues();
      const HEADER_ROW = 7;
      const headers = values[HEADER_ROW];
      const phoneIndex = headers.findIndex(h => h.toString().toLowerCase().includes('phone'));
      let pinIndex = headers.findIndex(h => h.toString().toLowerCase().includes('pin'));

      // Create PIN column if doesn't exist
      if (pinIndex === -1) {
        pinIndex = headers.length;
        sheet.getRange(HEADER_ROW + 1, pinIndex + 1).setValue('PIN');
      }

      if (phoneIndex === -1) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'Phone column not found'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      const cleanPhone = phone.replace(/[\s\-\(\)]/g, '');

      // Find member row
      let foundRow = -1;
      for (let i = HEADER_ROW + 1; i < values.length; i++) {
        const rowPhone = values[i][phoneIndex]?.toString().replace(/[\s\-\(\)]/g, '');
        if (rowPhone && rowPhone.includes(cleanPhone.slice(-10))) {
          foundRow = i + 1;
          break;
        }
      }

      if (foundRow === -1) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'Phone number not found'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      // Check existing PIN
      const existingPin = sheet.getRange(foundRow, pinIndex + 1).getValue();
      if (existingPin && existingPin.toString().length === 4) {
        return ContentService.createTextOutput(JSON.stringify({
          success: false,
          message: 'PIN already exists. Contact admin to reset.'
        })).setMimeType(ContentService.MimeType.JSON);
      }

      // Store plain PIN (legacy - will be upgraded to encrypted)
      sheet.getRange(foundRow, pinIndex + 1).setValue(pin);

      return ContentService.createTextOutput(JSON.stringify({
        success: true,
        message: 'PIN successfully created'
      })).setMimeType(ContentService.MimeType.JSON);
    }

  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({
      success: false,
      message: 'Server error: ' + error.toString()
    })).setMimeType(ContentService.MimeType.JSON);
  }
}

