/**
 * Get OAuth2 access token for FCM V1 API
 */
function getAccessToken() {
  const privateKey = FCM_V1_CONFIG.PRIVATE_KEY;
  const clientEmail = FCM_V1_CONFIG.CLIENT_EMAIL;

  const jwtHeader = JSON.stringify({
    alg: 'RS256',
    typ: 'JWT'
  });

  const now = Math.floor(Date.now() / 1000);
  const jwtClaim = JSON.stringify({
    iss: clientEmail,
    scope: 'https://www.googleapis.com/auth/firebase.messaging',
    aud: 'https://oauth2.googleapis.com/token',
    exp: now + 3600,
    iat: now
  });

  const jwtHeaderBase64 = Utilities.base64EncodeWebSafe(jwtHeader);
  const jwtClaimBase64 = Utilities.base64EncodeWebSafe(jwtClaim);
  const signatureInput = jwtHeaderBase64 + '.' + jwtClaimBase64;

  const signature = Utilities.computeRsaSha256Signature(signatureInput, privateKey);
  const signatureBase64 = Utilities.base64EncodeWebSafe(signature);

  const jwt = signatureInput + '.' + signatureBase64;

  const options = {
    method: 'post',
    payload: {
      grant_type: 'urn:ietf:params:oauth:grant-type:jwt-bearer',
      assertion: jwt
    },
    muteHttpExceptions: true
  };

  const response = UrlFetchApp.fetch('https://oauth2.googleapis.com/token', options);
  const result = JSON.parse(response.getContentText());

  return result.access_token;
}

/**
 * Send push notification using FCM V1 API
 * @param {string} token - FCM device token
 * @param {string} title - Notification title
 * @param {string} body - Notification body
 */
function sendPushNotificationV1(token, title, body) {
  if (!token || token === '') {
    Logger.log('No FCM token available, skipping push notification');
    return { success: false, reason: 'no_token' };
  }

  try {
    // Get access token
    const accessToken = getAccessToken();

    if (!accessToken) {
      Logger.log('Failed to get access token');
      return { success: false, reason: 'auth_failed' };
    }

    // Prepare FCM V1 API request
    const projectId = FCM_V1_CONFIG.PROJECT_ID;
    const url = `https://fcm.googleapis.com/v1/projects/${projectId}/messages:send`;

    const payload = {
      message: {
        token: token,
        notification: {
          title: title,
          body: body
        },
        webpush: {
          fcm_options: {
            link: FCM_V1_CONFIG.APP_URL
          },
          notification: {
            icon: '/logo192.png',
            badge: '/logo192.png'
          }
        },
        android: {
          priority: 'high',
          notification: {
            click_action: FCM_V1_CONFIG.APP_URL
          }
        }
      }
    };

    const options = {
      method: 'post',
      headers: {
        'Authorization': 'Bearer ' + accessToken,
        'Content-Type': 'application/json'
      },
      payload: JSON.stringify(payload),
      muteHttpExceptions: true
    };

    const response = UrlFetchApp.fetch(url, options);
    const result = JSON.parse(response.getContentText());

    if (response.getResponseCode() === 200) {
      Logger.log('Push notification sent successfully');
      return { success: true, result: result };
    } else {
      Logger.log('Push notification failed: ' + JSON.stringify(result));
      return { success: false, reason: 'fcm_error', result: result };
    }

  } catch (error) {
    Logger.log('Error sending push notification: ' + error.toString());
    return { success: false, reason: 'exception', error: error.toString() };
  }
}

/**
 * Get FCM token for a member by phone number
 */
function getFCMToken(phone, data, indices) {
  if (!indices.fcmToken || indices.fcmToken === -1) {
    return null;
  }

  const cleanPhone = phone.toString().replace(/[\s\-\(\)]/g, '');

  for (let i = 0; i < data.length; i++) {
    const rowPhone = data[i][indices.phone]?.toString().replace(/[\s\-\(\)]/g, '');
    if (rowPhone && rowPhone.includes(cleanPhone.slice(-10))) {
      return data[i][indices.fcmToken] || null;
    }
  }

  return null;
}

class NotificationSystem {
  constructor() {
    this.spreadsheet = SpreadsheetApp.getActiveSpreadsheet();
    this.mainSheet = this.spreadsheet.getSheetByName(CONFIG.SHEET_NAME);
  }

  getColumnIndices(headers) {
    return {
      email: headers.indexOf("Email"),
      firstName: headers.indexOf("First Name"),
      lastName: headers.indexOf("Last Name"),
      expirationDate: headers.indexOf("Expiration Date"),
      phone: headers.indexOf("Phone"),
      fcmToken: headers.indexOf("Notification Token")
    };
  }

  formatDate(date) {
    return Utilities.formatDate(date, Session.getScriptTimeZone(), "MMMM dd, yyyy");
  }

  processNotifications() {
    if (!this.mainSheet) throw new Error(`Sheet "${CONFIG.SHEET_NAME}" not found.`);
    const data = this.mainSheet.getDataRange().getValues();
    if (data.length <= CONFIG.HEADERS_ROW) throw new Error("No data found in the sheet.");

    const headers = data[CONFIG.HEADERS_ROW - 1];
    const indices = this.getColumnIndices(headers);

    this.allData = data.slice(CONFIG.DATA_START_ROW - 1);

    for (let i = CONFIG.DATA_START_ROW - 1; i < data.length; i++) {
      this.processRow(data[i], indices);
    }
  }

  processRow(row, indices) {
    const email = row[indices.email];
    const firstName = row[indices.firstName] || '';
    const lastName = row[indices.lastName] || '';
    const phone = row[indices.phone];
    const expirationDateCell = row[indices.expirationDate];

    if (!expirationDateCell || !email) return;

    const expirationDate = new Date(expirationDateCell);
    if (isNaN(expirationDate.getTime())) return;

    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const daysUntilExpiration = Math.round((expirationDate - today) / (24 * 60 * 60 * 1000));

    let notificationType = null;

    if (daysUntilExpiration === 0) {
      notificationType = 'today';
    } else if (daysUntilExpiration === 3) {
      notificationType = 'threeDaysBefore';
    } else if (daysUntilExpiration === 7) {
      notificationType = 'sevenDaysBefore';
    } else if (daysUntilExpiration === -CONFIG.FOLLOW_UP_WINDOW) {
      notificationType = 'followUp';
    }

    if (notificationType) {
      this.sendNotification(email, firstName, lastName, phone, this.formatDate(expirationDate), notificationType, indices);
    }
  }

  sendNotification(email, firstName, lastName, phone, expirationDate, notificationType, indices) {
    const template = EMAIL_TEMPLATES[notificationType];
    if (!template) return;

    const emailData = {
      firstName: firstName || '',
      lastName: lastName || '',
      expirationDate: expirationDate
    };

    const subject = template.subject.replace(/{(.*?)}/g, (_, key) => emailData[key]);
    const body = template.body.replace(/{(.*?)}/g, (_, key) => emailData[key]);

    // Send email
    try {
      GmailApp.sendEmail(email, subject, body, {
        from: CONFIG.SENDER_EMAIL,
        name: 'CrossFit Lagos',
        replyTo: 'noreply@crossfitlagos.com'
      });
      Logger.log('Email sent to: ' + email + ' (' + notificationType + ')');
    } catch (error) {
      Logger.log('Error sending email to ' + email + ': ' + error.toString());
    }

    // Send push notification using V1 API
    if (phone) {
      const fcmToken = getFCMToken(phone, this.allData, indices);
      if (fcmToken) {
        const pushTemplate = PUSH_TEMPLATES[notificationType];
        if (pushTemplate) {
          const pushResult = sendPushNotificationV1(fcmToken, pushTemplate.title, pushTemplate.body);
          if (pushResult.success) {
            Logger.log('Push notification sent to: ' + phone + ' (' + notificationType + ')');
          } else {
            Logger.log('Push notification failed for: ' + phone + ' - Reason: ' + pushResult.reason);
          }
        }
      } else {
        Logger.log('No FCM token for: ' + phone + ' (push notification skipped)');
      }
    }
  }
}

